function doImport(raw){const d=decodeCompact(raw.trim());if(!d)return false;if(d.t==='all'&&d.F){F=d.F;LB=d.LB||{};reqLB=d.reqLB||{}}else{LB=d.LB||{};if(d.reqLB)Object.assign(reqLB,d.reqLB)}autoReq();render();return true}
